import json
import pickle

def lambda_handler(event, context):
    try:
        # Deserialize the JSON payload
        payload = json.loads(event['body'])
        
        # Process the user actions
        user_actions = payload.get('user_actions', [])
        
        # Example processing: Serialize the actions using pickle
        serialized_actions = pickle.dumps(user_actions)
        
        # Return a successful response
        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Actions processed successfully', 'data': serialized_actions.hex()})
        }
        
    except Exception as e:
        # Handle exceptions and return an error response
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }